import socket
import time


def fetch_banner(host, port):
    delay = 0.02
    last_error = None
    for _ in range(6):
        try:
            with socket.create_connection((host, port), timeout=0.2) as sock:
                return sock.recv(64).decode("ascii")
        except ConnectionRefusedError as exc:
            last_error = exc
            time.sleep(delay)
            delay *= 2
    raise last_error

